type User struct {
    Name  string `json:"name"`
    Email string `json:"email"`
    Age   int    `json:"age"`
}

func main() {
    user := User{
        Name: "고퍼", Email: "go@go.dev",
        Age: 10,
    }
    // 구조체 → JSON 바이트
    data, err := json.Marshal(user)
    if err != nil { log.Fatal(err) }
    fmt.Println(string(data))
    // {"name":"고퍼","email":"go@go.dev","age":10}

jsonStr := `{
    "name": "고퍼",
    "email": "go@go.dev",
    "age": 10
}`

var user User
err := json.Unmarshal(
    []byte(jsonStr), &user,
)
if err != nil {
    log.Fatal(err)
}
fmt.Println(user.Name)  // 고퍼
fmt.Println(user.Email) // go@go.dev
fmt.Println(user.Age)   // 10

type Product struct {
    ID    int    `json:"id"`
    Name  string `json:"name"`
    // omitempty: 빈 값이면 JSON에서 제외
    Desc  string `json:"desc,omitempty"`
    // -: JSON 변환에서 완전 제외
    Secret string `json:"-"`
}
p := Product{ID: 1, Name: "Go북"}
data, _ := json.Marshal(p)
fmt.Println(string(data))
// {"id":1,"name":"Go북"}
// desc 빈값 → 생략됨!
// Secret → 완전 제외!

type Address struct {
    City string `json:"city"`
    Zip  string `json:"zip"`
}
type Person struct {
    Name    string  `json:"name"`
    Address Address `json:"address"`
}
p := Person{
    Name: "고퍼",
    Address: Address{
        City: "서울", Zip: "06000",
    },
}
data, _ := json.MarshalIndent(
    p, "", "  ",
)
fmt.Println(string(data))

// 구조체 없이 map으로 처리
jsonStr := `{"name":"Go","ver":1.21}`

var m map[string]any
json.Unmarshal(
    []byte(jsonStr), &m,
)
fmt.Println(m["name"]) // Go

// map → JSON
data := map[string]any{
    "status": "ok",
    "count":  42,
}
result, _ := json.Marshal(data)
fmt.Println(string(result))
// {"count":42,"status":"ok"}

